/// implements xev.Callback and is the default value for completions.
pub fn NoopCallback(comptime T: type) Callback(T) {
    return (struct {
        pub fn noopCallback(
            _: ?*anyopaque,
            _: *T.Loop,
            _: *T.Completion,
            _: T.Result,
        ) CallbackAction {
            return .disarm;
        }
    }).noopCallback;
